class APMTransaction:
    """Represents a single transaction being monitored."""

    def __init__(self, name, transaction_type="request"):
        self.name = name
        self.transaction_type = transaction_type
        self.start_time = time.time()
        self.end_time = None
        self.duration_ms = None
        self.result = None
        self.spans = []
        self.context = {}
        self.errors = []
        self.stack_traces = []
        self.id = id(self)

    def end(self, result="success"):
        self.end_time = time.time()
        self.duration_ms = (self.end_time - self.start_time) * 1000
        self.result = result

    def set_context(self, context_data):
        self.context.update(context_data)

    def to_dict(self):
        return {
            "id": self.id,
            "name": self.name,
            "type": self.transaction_type,
            "start_time": datetime.fromtimestamp(self.start_time).isoformat(),
            "end_time": datetime.fromtimestamp(self.end_time).isoformat() if self.end_time else None,
            "duration_ms": self.duration_ms,
            "result": self.result,
            "spans": [s.to_dict() for s in self.spans],
            "context": self.context,
            "errors": self.errors,
            "stack_traces": self.stack_traces,
        }


class APMSpan:
    """Represents a span within a transaction (e.g., a DB query, HTTP call)."""

    def __init__(self, name, span_type="custom", subtype=None, action=None):
        self.name = name
        self.span_type = span_type
        self.subtype = subtype
        self.action = action
        self.start_time = time.time()
        self.end_time = None
        self.duration_ms = None
        self.context = {}
        self.stack_trace = None

    def end(self):
        self.end_time = time.time()
        self.duration_ms = (self.end_time - self.start_time) * 1000

    def set_context(self, context_data):
        self.context.update(context_data)

    def capture_stack_trace(self):
        import traceback
        self.stack_trace = traceback.format_stack()

    def to_dict(self):
        return {
            "name": self.name,
            "type": self.span_type,
            "subtype": self.subtype,
            "action": self.action,
            "start_time": datetime.fromtimestamp(self.start_time).isoformat(),
            "duration_ms": self.duration_ms,
            "context": self.context,
            "stack_trace": self.stack_trace,
        }


class CustomAPMClient:
    """Custom APM client that captures and stores performance data."""

    def __init__(self, config=None):
        self.config = config or {}
        self.service_name = self.config.get("SERVICE_NAME", "my-python-app")
        self.environment = self.config.get("ENVIRONMENT", "development")
        self.capture_body = self.config.get("CAPTURE_BODY", "all")
        self.capture_headers = self.config.get("CAPTURE_HEADERS", True)
        self.collect_db_queries = self.config.get("COLLECT_DB_QUERIES", True)
        self.stack_trace_limit = self.config.get("STACK_TRACE_LIMIT", 50)
        self.transactions = []
        self.current_transaction = None
        self.errors = []
        self._storage_file = self.config.get("STORAGE_FILE", "apm_data.json")

        logger.info(
            f"Custom APM Client initialized for service '{self.service_name}' "
            f"in '{self.environment}' environment"
        )

    def begin_transaction(self, transaction_type="request", name=None):
        transaction = APMTransaction(name=name or "unnamed", transaction_type=transaction_type)
        self.current_transaction = transaction
        logger.debug(f"Transaction started: {transaction.name}")
        return transaction

    def end_transaction(self, name=None, result="success"):
        if self.current_transaction:
            if name:
                self.current_transaction.name = name
            self.current_transaction.end(result=result)
            self.transactions.append(self.current_transaction)
            logger.info(
                f"Transaction ended: {self.current_transaction.name} "
                f"- Duration: {self.current_transaction.duration_ms:.2f}ms "
                f"- Result: {result}"
            )
            self._persist_transaction(self.current_transaction)
            transaction = self.current_transaction
            self.current_transaction = None
            return transaction
        return None

    def begin_span(self, name, span_type="custom", subtype=None, action=None):
        span = APMSpan(name=name, span_type=span_type, subtype=subtype, action=action)
        span.capture_stack_trace()
        if self.current_transaction:
            self.current_transaction.spans.append(span)
        logger.debug(f"Span started: {name} (type: {span_type})")
        return span

    def end_span(self, span):
        if span:
            span.end()
            logger.debug(f"Span ended: {span.name} - Duration: {span.duration_ms:.2f}ms")

    def capture_exception(self, exc_info=None):
        import traceback
        import sys

        if exc_info is None:
            exc_info = sys.exc_info()

        error_data = {
            "timestamp": datetime.now().isoformat(),
            "exception": {
                "type": exc_info[0].__name__ if exc_info[0] else "Unknown",
                "message": str(exc_info[1]) if exc_info[1] else "Unknown error",
                "stacktrace": traceback.format_exception(*exc_info) if all(exc_info) else [],
            },
            "transaction_name": self.current_transaction.name if self.current_transaction else None,
        }

        self.errors.append(error_data)

        if self.current_transaction:
            self.current_transaction.errors.append(error_data)
            self.current_transaction.stack_traces.append(
                traceback.format_exception(*exc_info) if all(exc_info) else []
            )

        logger.error(f"Exception captured: {error_data['exception']['type']}: {error_data['exception']['message']}")
        return error_data

    def capture_message(self, message, level="info"):
        msg_data = {
            "timestamp": datetime.now().isoformat(),
            "message": message,
            "level": level,
            "transaction_name": self.current_transaction.name if self.current_transaction else None,
        }
        logger.log(getattr(logging, level.upper(), logging.INFO), f"APM Message: {message}")
        return msg_data

    def set_transaction_context(self, context_data):
        if self.current_transaction:
            self.current_transaction.set_context(context_data)

    def _persist_transaction(self, transaction):
        """Persist transaction data to file for later analysis."""
        try:
            existing_data = []
            if os.path.exists(self._storage_file):
                with open(self._storage_file, 'r') as f:
                    try:
                        existing_data = json.load(f)
                    except json.JSONDecodeError:
                        existing_data = []

            existing_data.append(transaction.to_dict())

            # Keep only last 1000 transactions
            if len(existing_data) > 1000:
                existing_data = existing_data[-1000:]

            with open(self._storage_file, 'w') as f:
                json.dump(existing_data, f, indent=2, default=str)
        except Exception as e:
            logger.error(f"Failed to persist transaction data: {e}")

    def get_stats(self):
        """Get aggregated performance statistics."""
        if not self.transactions:
            return {"message": "No transactions recorded yet"}

        durations = [t.duration_ms for t in self.transactions if t.duration_ms is not None]
        error_count = sum(len(t.errors) for t in self.transactions)

        return {
            "service_name": self.service_name,
            "environment": self.environment,
            "total_transactions": len(self.transactions),
            "total_errors": error_count,
            "avg_duration_ms": sum(durations) / len(durations) if durations else 0,
            "min_duration_ms": min(durations) if durations else 0,
            "max_duration_ms": max(durations) if durations else 0,
            "p95_duration_ms": sorted(durations)[int(len(durations) * 0.95)] if durations else 0,
            "error_rate": error_count / len(self.transactions) if self.transactions else 0,
            "transactions_per_type": self._count_by_type(),
        }

    def _count_by_type(self):
        counts = {}
        for t in self.transactions:
            counts[t.transaction_type] = counts.get(t.transaction_type, 0) + 1
        return counts


