def apm_trace(name=None, span_type="custom", subtype=None, action=None):
    """Decorator to trace function execution as an APM span."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            span_name = name or f"{func.__module__}.{func.__qualname__}"
            span = apm_client.begin_span(
                name=span_name,
                span_type=span_type,
                subtype=subtype,
                action=action
            )
            span.set_context({
                "function": {
                    "name": func.__qualname__,
                    "module": func.__module__,
                    "args_count": len(args),
                    "kwargs_keys": list(kwargs.keys()),
                }
            })

            try:
                result = func(*args, **kwargs)
                apm_client.end_span(span)
                return result
            except Exception as e:
                apm_client.capture_exception()
                apm_client.end_span(span)
                raise
        return wrapper
    return decorator


def apm_transaction(name=None, transaction_type="custom"):
    """Decorator to trace function execution as an APM transaction."""
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            tx_name = name or f"{func.__module__}.{func.__qualname__}"
            apm_client.begin_transaction(transaction_type=transaction_type, name=tx_name)

            try:
                result = func(*args, **kwargs)
                apm_client.end_transaction(name=tx_name, result="success")
                return result
            except Exception as e:
                apm_client.capture_exception()
                apm_client.end_transaction(name=tx_name, result="error")
                raise
        return wrapper
    return decorator


